.card.out-of-stock {
    opacity: 0.6;
    filter: grayscale(1);
    border-color: var(--danger);
}

.card-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.platform-badge {
    background: var(--bg-secondary);
    padding: 0.4rem 1rem;
    border-radius: 20px;
    font-size: 0.85rem;
    font-weight: 600;
    letter-spacing: 0.5px;
    text-transform: uppercase;
}

/* Specific Platform Colors */
.platform-blinkit {
    color: #facc15;
}

.platform-instamart {
    color: #f97316;
}

.platform-bigbasket {
    color: #84cc16;
}

.product-name {
    font-size: 1.25rem;
    font-weight: 600;
    line-height: 1.3;
    margin-top: 0.5rem;
}

.price-container {
    display: flex;
    align-items: baseline;
    gap: 5px;
    margin-top: auto;
    padding-top: 1rem;
    border-top: 1px solid var(--glass-border);
}

.currency {
    font-size: 1.2rem;
    color: var(--text-secondary);
    font-weight: 400;
}

.price {
    font-size: 2.5rem;
    font-weight: 800;
    color: var(--text-primary);
}

.card.best-value .price {
    color: var(--success);
}

.status-badge {
    display: inline-block;
    padding: 0.3rem 0.8rem;
    border-radius: 12px;
    font-size: 0.8rem;
    font-weight: 600;
    margin-top: 0.5rem;
    width: fit-content;
}

.status-in-stock {
    background: rgba(16, 185, 129, 0.1);
    color: var(--success);
}

.status-oos {
    background: rgba(239, 68, 68, 0.1);
    color: var(--danger);
}

.visit-btn {
    width: 100%;
    display: block;
    text-align: center;
    padding: 0.8rem;
    background: var(--bg-secondary);
    color: var(--text-primary);
    text-decoration: none;
    border-radius: 10px;
    font-weight: 600;
    margin-top: 1rem;
    transition: background 0.2s;
}

.visit-btn:hover {
    background: rgba(255, 255, 255, 0.1);
}

/* Animations */
@keyframes spin {
    100% {
        transform: rotate(360deg);
    }
}

@keyframes fadeIn {
    from {
        opacity: 0;
    }

    to {
        opacity: 1;
    }
}

@keyframes fadeInDown {
    from {
        opacity: 0;
        transform: translateY(-20px);
    }

    to {
        opacity: 1;
        transform: translateY(0);
    }
}

@keyframes slideUp {
    from {
        opacity: 0;
        transform: translateY(30px);
    }

    to {
        opacity: 1;
        transform: translateY(0);
    }
}

/* Responsive */
@media (max-width: 768px) {
    .logo {
        font-size: 2.5rem;
    }

    .search-box {
        flex-direction: column;
        border-radius: 16px;
        padding: 1rem;
        gap: 1rem;
    }

    .search-icon {
        display: none;
    }

    .search-box input {
        width: 100%;
        text-align: center;
    }

    .btn-search {
        width: 100%;
    }
}

